SELECT COUNT(*) FROM om_order_m o JOIN om_order_item_m i ON i.order_id = o.order_id AND i.regist_dt = o.regist_dt LEFT JOIN om_mall_store_m s ON s.mall_cd = o.mall_cd AND s.corporation_cd = o.corporation_cd AND s.store_cd = o.store_cd
AND o.corporation_cd = #{corporationCd}
AND s.store_id = #{storeId}
AND o.sales_type_cd = #{salesTypeCd}
AND o.regist_dt >= (#{orderDtFrom}::date)
AND o.regist_dt <= (#{orderDtTo}::date)
AND o.order_dt >= (#{orderDtFrom}::date)
AND o.order_dt <= (#{orderDtTo}::date)
AND i.is_deleted = true

SELECT DISTINCT o.order_id AS orderId , TO_CHAR(o.regist_dt, 'YYYY-MM-DD') AS registDt FROM om_order_m o JOIN om_order_item_m i ON i.order_id = o.order_id AND i.regist_dt = o.regist_dt AND i.is_deleted = false LEFT JOIN om_mall_store_m s ON s.mall_cd = o.mall_cd AND s.corporation_cd = o.corporation_cd AND s.store_cd = o.store_cd WHERE o.corporation_cd = #{corporationCd} AND o.order_process_status = 'ORDER_RECEIVED'
AND s.store_id = #{storeId}
AND o.sales_type_cd = #{salesTypeCd}
AND o.regist_dt >= (#{orderDtFrom}::date)
AND o.regist_dt <= (#{orderDtTo}::date)
AND o.order_dt >= (#{orderDtFrom}::date)
AND o.order_dt <= (#{orderDtTo}::date)
AND o.order_no LIKE '%' || #{searchKeyword} || '%'
AND i.item_order_no = #{searchKeyword}
AND o.combined_ship_no = #{searchKeyword}
AND i.product_cd = #{searchKeyword}
AND i.product_nm LIKE '%' || #{searchKeyword} || '%'
AND (o.order_info->>'ordererNm') LIKE '%' || #{searchKeyword} || '%'
AND (o.order_info->>'receiverNm') LIKE '%' || #{searchKeyword} || '%'
AND o.order_id = (#{searchKeyword}::bigint)
ORDER BY o.order_id, TO_CHAR(o.regist_dt, 'YYYY-MM-DD')

SELECT DISTINCT o.order_id AS orderId , TO_CHAR(o.regist_dt, 'YYYY-MM-DD') AS registDt FROM om_order_m o JOIN om_order_item_m i ON i.order_id = o.order_id AND i.regist_dt = o.regist_dt AND i.is_deleted = false LEFT JOIN om_mall_store_m s ON s.mall_cd = o.mall_cd AND s.corporation_cd = o.corporation_cd AND s.store_cd = o.store_cd WHERE o.corporation_cd = #{corporationCd} AND o.order_process_status = 'PROCESSING'
AND s.store_id = #{storeId}
AND o.sales_type_cd = #{salesTypeCd}
AND o.regist_dt >= (#{orderDtFrom}::date)
AND o.regist_dt <= (#{orderDtTo}::date)
AND o.order_dt >= (#{orderDtFrom}::date)
AND o.order_dt <= (#{orderDtTo}::date)
AND o.order_no LIKE '%' || #{searchKeyword} || '%'
AND i.item_order_no = #{searchKeyword}
AND o.combined_ship_no = #{searchKeyword}
AND i.product_cd = #{searchKeyword}
AND i.product_nm LIKE '%' || #{searchKeyword} || '%'
AND (o.order_info->>'ordererNm') LIKE '%' || #{searchKeyword} || '%'
AND (o.order_info->>'receiverNm') LIKE '%' || #{searchKeyword} || '%'
AND o.order_id = (#{searchKeyword}::bigint)
ORDER BY o.order_id, TO_CHAR(o.regist_dt, 'YYYY-MM-DD')

SELECT o.order_id AS orderId , TO_CHAR(o.regist_dt, 'YYYY-MM-DD') AS registDt , o.store_cd AS storeCd , (o.order_info->>'receiverNm') AS receiverNm , (o.order_info->>'receiverTel') AS receiverTel , (o.order_info->>'receiverAddr') AS receiverAddr , (o.order_info->>'receiverAddr2') AS receiverAddr2 , (o.order_info->>'receiverZip') AS receiverZip FROM om_order_m o INNER JOIN (VALUES
(#{k.orderId}, (#{k.registDt})::date)
) AS t(order_id, regist_dt) ON o.order_id = t.order_id AND o.regist_dt = t.regist_dt WHERE o.corporation_cd = #{corporationCd}
AND o.store_cd = #{storeCd}

SELECT o.order_id AS orderId , TO_CHAR(o.regist_dt, 'YYYY-MM-DD') AS registDt , o.order_process_status AS orderProcessStatus , o.order_process_status_by AS orderProcessStatusBy , TO_CHAR(o.order_process_status_dt, 'YYYY-MM-DD HH24:MI:SS') AS orderProcessStatusDt FROM om_order_m o INNER JOIN (VALUES
(#{k.orderId}, (#{k.registDt})::date)
) AS t(order_id, regist_dt) ON o.order_id = t.order_id AND o.regist_dt = t.regist_dt WHERE o.corporation_cd = #{corporationCd}
AND o.store_cd = #{storeCd}

WITH lock AS (
    SELECT pg_advisory_xact_lock(hashtext(#{registDt} || '|' || #{corporationCd} || '|' || #{mallCd} || '|' || #{storeCd})::bigint)
)
SELECT 'M-' || to_char((#{registDt})::date, 'YYYYMMDD') || '-' || lpad(
    (COALESCE((
        SELECT MAX((split_part(o.order_no, '-', 3))::int)
        FROM om_order_m o
        WHERE o.regist_dt = (#{registDt})::date
          AND o.corporation_cd = #{corporationCd}
          AND o.mall_cd = #{mallCd}
          AND o.store_cd = #{storeCd}
          AND o.order_no LIKE 'M-' || to_char((#{registDt})::date, 'YYYYMMDD') || '-%'
    ), 0) + 1)::text, 4, '0')

mapper.insert:
INSERT INTO om_order_m (
    order_id, corporation_cd, mall_cd, store_cd, order_dt, regist_dt, order_no,
    combined_ship_no, sales_type_cd, order_process_status, order_type_cd, order_info,
    created_at, updated_at, created_by, updated_by
) VALUES (
    #{orderId}, #{corporationCd}, #{mallCd}, #{storeCd}, (#{orderDt}::date), (#{registDt}::date), #{orderNo},
    NULL, #{salesTypeCd}, 'ORDER_RECEIVED', COALESCE(NULLIF(TRIM(#{orderTypeCd}), ''), 'NORMAL'),
    COALESCE(#{orderInfo}::jsonb, '{}'::jsonb),
    CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, #{createdBy}, #{updatedBy}
)

INSERT INTO om_order_item_m (
    order_id, regist_dt, line_no, item_order_no, product_cd, product_nm,
    line_qty, line_amount, line_discount_amount, line_payload,
    is_deleted, created_at, updated_at, created_by, updated_by
) VALUES (
    #{orderId}, (#{registDt}::date), #{lineNo}, #{itemOrderNo}, #{productCd}, #{productNm},
    #{lineQty}, #{lineAmount}, COALESCE(#{lineDiscountAmount}, 0),
    COALESCE(#{linePayload}::jsonb, '{}'::jsonb),
    false, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, #{createdBy}, #{updatedBy}
)

