UPDATE om_order_m o
   SET order_process_status = #{orderProcessStatus}
     , order_process_status_dt = CURRENT_TIMESTAMP
     , order_process_status_by = #{orderProcessStatusBy}
     , combined_ship_no = v.combined_ship_no
     , updated_at = CURRENT_TIMESTAMP
 FROM (VALUES

    (#{k.orderId}, (#{k.registDt})::date, #{k.combinedShipNo})

 ) AS v(order_id, regist_dt, combined_ship_no)
 WHERE o.order_id = v.order_id AND o.regist_dt = v.regist_dt
   AND o.corporation_cd = #{corporationCd}

   AND o.store_cd = #{storeCd}


   AND o.order_process_status = #{expectedCurrentStatus}

mapper.select:
SELECT order_id AS orderId , TO_CHAR(regist_dt, 'YYYY-MM-DD') AS registDt , line_no AS lineNo , item_order_no AS itemOrderNo , product_cd AS productCd , product_nm AS productNm , line_qty AS lineQty , line_amount AS lineAmount , line_discount_amount AS lineDiscountAmount , line_payload::text AS linePayload , TO_CHAR(created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt , TO_CHAR(updated_at, 'YYYY-MM-DD HH24:MI:SS') AS updatedAt , created_by AS createdBy , updated_by AS updatedBy FROM om_order_item_m WHERE order_id = #{orderId} AND regist_dt = (#{registDt}::date) AND is_deleted = false AND EXISTS ( SELECT 1 FROM om_order_m o WHERE o.order_id = om_order_item_m.order_id AND o.regist_dt = om_order_item_m.regist_dt AND o.corporation_cd = #{corporationCd}
AND o.store_cd = #{storeCd}
) ORDER BY line_no ASC

mapper.update:
UPDATE om_order_m
   SET order_no              = #{orderNo}
     , combined_ship_no      = #{combinedShipNo}
     , order_dt              = (#{orderDt}::date)
     , sales_type_cd         = #{salesTypeCd}
     , order_process_status  = #{orderProcessStatus}
     , order_type_cd         = #{orderTypeCd}
     , order_info            = COALESCE(NULLIF(TRIM(COALESCE(#{orderInfo}, '')), '')::jsonb, '{}'::jsonb) || jsonb_build_object(
         'receiverNm', (#{receiverNm})::text, 'receiverTel', (#{receiverTel})::text, 'receiverMobile', (#{receiverMobile})::text,
         'receiverAddr', (#{receiverAddr})::text, 'receiverAddr2', (#{receiverAddr2})::text, 'receiverZip', (#{receiverZip})::text,
         'ordererNm', (#{ordererNm})::text, 'ordererUserId', (#{ordererUserId})::text, 'ordererTel', (#{ordererTel})::text, 'ordererMobile', (#{ordererMobile})::text,
         'memo', (#{memo})::text,
         'deliveryFee', (#{deliveryFee})::numeric, 'paymentMethodCd', (#{paymentMethodCd})::text
       )
     , updated_at            = CURRENT_TIMESTAMP
 WHERE order_id = #{orderId}
   AND regist_dt = (#{registDt}::date)
   AND corporation_cd = #{corporationCd}
   AND store_cd = #{storeCd}

UPDATE om_order_item_m
   SET item_order_no       = #{item.itemOrderNo}
     , product_cd          = #{item.productCd}
     , product_nm          = #{item.productNm}
     , line_qty            = #{item.lineQty}
     , line_amount         = #{item.lineAmount}
     , line_discount_amount = #{item.lineDiscountAmount}
     , line_payload         = COALESCE(#{item.linePayload}::jsonb, '{}'::jsonb)
     , updated_at          = CURRENT_TIMESTAMP
 WHERE order_id = #{item.orderId}
   AND regist_dt = (#{item.registDt}::date)
   AND line_no   = #{item.lineNo}
   AND EXISTS (
     SELECT 1 FROM om_order_m o
      WHERE o.order_id = om_order_item_m.order_id AND o.regist_dt = om_order_item_m.regist_dt
        AND o.corporation_cd = #{corporationCd}

        AND o.store_cd = #{storeCd}

   )

UPDATE om_order_m
   SET order_process_status = #{orderProcessStatus}
     , order_process_status_dt = CURRENT_TIMESTAMP
     , updated_at = CURRENT_TIMESTAMP
 WHERE order_id = #{orderId}
   AND regist_dt = (#{registDt}::date)
   AND corporation_cd = #{corporationCd}

   AND store_cd = #{storeCd}

UPDATE om_order_m o
   SET order_process_status = #{orderProcessStatus}
     , order_process_status_dt = CURRENT_TIMESTAMP
     , updated_at = CURRENT_TIMESTAMP
 FROM (VALUES

    (#{k.orderId}, (#{k.registDt})::date)

 ) AS t(order_id, regist_dt)
 WHERE o.order_id = t.order_id AND o.regist_dt = t.regist_dt
   AND o.corporation_cd = #{corporationCd}

   AND o.store_cd = #{storeCd}




       AND o.order_process_status = #{expectedCurrentStatus}


       AND o.order_process_status IN ('PROCESSING', 'SHIP_READY')

UPDATE om_order_m o
   SET order_process_status = 'ORDER_RECEIVED'
     , order_process_status_dt = CURRENT_TIMESTAMP
     , combined_ship_no = NULL
     , updated_at = CURRENT_TIMESTAMP
