  JOIN (VALUES

    (#{k.orderId}, (#{k.registDt})::date)

  ) AS t(order_id, regist_dt) ON o.order_id = t.order_id AND o.regist_dt = t.regist_dt
 WHERE o.corporation_cd = #{corporationCd}

