UPDATE om_order_item_m
   SET is_deleted = #{isDeleted}
     , updated_at = CURRENT_TIMESTAMP
 WHERE order_id = #{orderId}
   AND regist_dt = (#{registDt}::date)
   AND line_no = #{lineNo}
   AND EXISTS (
     SELECT 1 FROM om_order_m o
      WHERE o.order_id = om_order_item_m.order_id AND o.regist_dt = om_order_item_m.regist_dt
        AND o.corporation_cd = #{corporationCd}

        AND o.store_cd = #{storeCd}

   )

UPDATE om_order_item_m i
   SET is_deleted = #{isDeleted}
     , updated_at = CURRENT_TIMESTAMP
 FROM (
   SELECT t.order_id, t.regist_dt, t.line_no
     FROM (VALUES

    (#{k.orderId}, (#{k.registDt})::date, #{k.lineNo})

     ) AS t(order_id, regist_dt, line_no)
     JOIN om_order_m o ON o.order_id = t.order_id AND o.regist_dt = t.regist_dt
       AND o.corporation_cd = #{corporationCd}

       AND o.store_cd = #{storeCd}

 ) AS allowed
 WHERE i.order_id = allowed.order_id AND i.regist_dt = allowed.regist_dt AND i.line_no = allowed.line_no
